function detectRecursiveTriggers(workflow: any): string[] {
  const triggers: string[] = [];
  const webhookNodes = workflow.nodes.filter((n: any) => n.type === 'n8n-nodes-base.webhook');
  const aiAgentNodes = workflow.nodes.filter((n: any) => n.type.includes('aiAgent'));

  webhookNodes.forEach((webhook: any) => {
    const connections = workflow.connections[webhook.id];
    if (connections?.main?.[0]?.some((targetId: string) => 
      aiAgentNodes.some((agent: any) => agent.id === targetId)
    )) {
      triggers.push(`Webhook ${webhook.name} → AI Agent recursion detected`);
    }
  });
  return triggers;
}

function detectTokenBloat(workflow: any): string[] {
  const issues: string[] = [];
  const memoryNodes = workflow.nodes.filter((n: any) => 
    n.type.includes('memory') || n.parameters.sessionId
  );

  memoryNodes.forEach((node: any) => {
    if (node.parameters.maxTokens && node.parameters.maxTokens > 50000) {
      issues.push(`Memory node ${node.name}: Excessive ${node.parameters.maxTokens} token limit`);
    }
    if (!node.parameters.summarization) {
      issues.push(`Memory node ${node.name}: No summarization enabled`);
    }
  });
  return issues;
}

function detectUnvalidatedOutputs(workflow: any): string[] {
  const issues: string[] = [];
  const aiNodes = workflow.nodes.filter((n: any) => n.type.includes('aiAgent'));

  aiNodes.forEach((aiNode: any) => {
    const connections = workflow.connections[aiNode.id];
    if (connections?.main?.[0]) {
      const targets = connections.main[0].map((t: any) => 
        workflow.nodes.find((n: any) => n.id === t.node)
      ).filter(Boolean);

      const hasValidation = targets.some((target: any) => 
        target.type.includes('code') || target.name.includes('validate')
      );
      if (!hasValidation && targets.some((t: any) => t.type.includes('tool'))) {
        issues.push(`AI Agent ${aiNode.name} → Tool without validation`);
      }
    }
  });
  return issues;
}

