// n8n Code Node - Cache Layer
const cache = $node["Cache"].all();
const inputData = $input.all();
const cacheKey = `${$execution.id}-${inputData[0].json.prompt || 'default'}`;

// Check cache first
const cached = cache.find((item: any) => item.json.cacheKey === cacheKey);
if (cached) {
  return [{ json: { ...cached.json, fromCache: true } }];
}

// Cache new response
return [{
  json: {
    ...inputData[0].json,
    cacheKey,
    timestamp: new Date().toISOString()
  }
}];

// n8n Code Node - Context Summarizer
const memoryContext = $node["Memory Window"].json();
const prompt = `Summarize this conversation context to under 2000 tokens, preserving key facts:\n\n${memoryContext.context.slice(0, 10000)}`;

// Use lightweight model for summarization
const summary = await $http.request({
  method: 'POST',
  url: 'https://api.openai.com/v1/chat/completions',
  headers: { Authorization: `Bearer ${$credentials.openAi.apiKey}` },
  body: {
    model: 'gpt-4o-mini',
    messages: [{ role: 'user', content: prompt }],
    max_tokens: 1500
  }
});

return [{
  json: {
    summarizedContext: summary.data.choices[0].message.content,
    tokenSavings: memoryContext.context.length - summary.data.usage.total_tokens
  }
}];

// n8n Code Node - Recursion Guard
const executionData = $execution;
const iterationCount = $node["IterationCounter"].json()?.count || 0;

const MAX_ITERATIONS = 5;
if (iterationCount >= MAX_ITERATIONS) {
  return [{
    json: {
      error: 'Max iterations exceeded',
      iterationCount,
      action: 'terminate'
    }
  }];
}

// Increment counter and continue
return [{
  json: {
    continue: true,
    iterationCount: iterationCount + 1,
    workflowData: $input.all()[0].json
  }
}];

