import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'your-project-id',
  webhookSecret: process.env.VEX_WEBHOOK_SECRET
});

// n8n Webhook Node after every AI Agent
export default async function costOptimizer($input: any, $execution: any) {
  const aiOutput = $input.first().json;

  // Vex auto-detection
  const issues = await vex.detect({
    framework: 'n8n',
    nodeType: 'aiAgent',
    inputTokens: aiOutput.usage?.prompt_tokens || 0,
    outputTokens: aiOutput.usage?.completion_tokens || 0,
    workflowId: $execution.workflow.id
  });

  if (issues.length > 0) {
    // Auto-fix: insert caching + summarization
    const remediation = await vex.remediate('cost-optimization', {
      workflowJson: $execution.workflow
    });

    // Log savings projection
    console.log(`Projected monthly savings: $${remediation.savings}`);

    return [{ json: { vexFixed: true, issues, remediation } }];
  }

  return [{ json: aiOutput }];
}
